  '{faqs}',
  '[{"q":"Can we guarantee 485 approval?","a":"No. Most eligible graduates approved but never guarantee."},{"q":"Post-Study Work vs Graduate Work?","a":"Post-Study Work based on degree level; Graduate Work requires skills assessment for nominated occupation."},{"q":"How long is 485?","a":"2–4 years depending on qualification level and stream—verify current rules."},{"q":"Can apply from outside Australia?","a":"Generally must hold eligible visa in Australia—verify current rules for offshore apply."},{"q":"Can include partner?","a":"Yes—partner and children can be included; additional fees and evidence."},{"q":"Path to PR?","a":"Australian work experience on 485 supports skilled migration points."},{"q":"When does 6 months start?","a":"From course completion date on official completion letter."},{"q":"Can work any job on 485?","a":"Yes—open work rights on Post-Study Work Stream."},{"q":"What is Description for this service?","a":"Temporary visa allowing international graduates to live, work, and study in Australia after completing eligible Australian qualification. Graduate Work Stream or Post-Study Work Stream."},{"q":"What is Eligible applicants for this service?","a":"Completed eligible CRICOS course · Valid student visa history · Applied within 6 months of completion · Competent English · Health and character"},{"q":"What is Stream selection for this service?","a":"Graduate Work Stream: skills assessment for nominated occupation. Post-Study Work Stream: based on qualification level (2–4 years)."},{"q":"Important note on Stream selection?","a":"Graduate Work Stream: skills assessment for nominated occupation. Post-Study Work Stream: based on qualification level (2–4 years)."},{"q":"What is Key authority for this service?","a":"Department of Home Affairs (Australia)"},{"q":"What is After approval for this service?","a":"Work freely in Australia. Pathway to skilled migration (189/190/491) with Australian experience."},{"q":"Is Completed eligible Australian qualification required?","a":"Completed eligible Australian qualification is typically required."},{"q":"Is Applied within 6 months of completion required?","a":"Critical deadline"},{"q":"Is Valid student visa compliance history required?","a":"Valid student visa compliance history is typically required."},{"q":"Is Competent English required?","a":"Competent English is typically required."},{"q":"Is Health insurance (if required) required?","a":"Health insurance (if required) is typically required."},{"q":"Is Skills assessment (Graduate Work Stream) required?","a":"If applicable stream"},{"q":"Is Health and character clearances required?","a":"Assess whether Health and character clearances is satisfied for this case."},{"q":"What is the Processing time?","a":"4–8w — Standard processing"},{"q":"What is the Government fee?","a":"AUD $2,000 — Verify current fee"},{"q":"What is the Our approval rate?","a":"93% — ~87% benchmark"},{"q":"What is the Required docs?","a":"10 — + completion evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & medical"},{"q":"What if the client has Missed 6-month deadline?","a":"Track completion date; apply within window"},{"q":"Why is Missed 6-month deadline a problem?","a":"Applied after 6 months from completion date."},{"q":"What if the client has Wrong stream selected?","a":"Assess qualification and occupation before stream choice"},{"q":"Why is Wrong stream selected a problem?","a":"Post-Study Work when Graduate Work needed or vice versa."}]'::jsonb
